% grid on;
% 
% %% Q heatmap over (psi_x, t_curr_position)
% N_test    = 20;
% psi_x_vec = linspace(0, 2*pi, N_test);
% 
% % Fix starting position at centre of grid for the sweep
% tx_fixed  = round(EnvPars.T_x / 2);
% ty_fixed  = round(EnvPars.T_y / 2);
% 
