%[text] #### Animation $\\Psi$ plane Agent vs Brute Force
%% Animation
agent_tx(1)=9;
agent_ty(1)=10;

figure; %[output:918d6367]
h_img = imagesc(1:EnvPars.T_x, 1:EnvPars.T_y, R_max_per_frame(:,:,1)); %[output:918d6367]
axis square; colorbar; hold on; %[output:918d6367]

% Common color scale across frames
clim([min(R_max_per_frame(:)), max(R_max_per_frame(:))]); %[output:918d6367]

% % --- Agent (black) ---
% Trail of past agent actions
h_trail_agent = plot(agent_tx(1), agent_ty(1), '-', ... %[output:918d6367]
                     'Color', [0 0 0 0.4], 'LineWidth', 1.2); %[output:918d6367]
% Past action markers (dim)
h_past_agent  = plot(agent_tx(1), agent_ty(1), 'ko', 'MarkerSize', 6, ... %[output:918d6367]
                     'MarkerFaceColor',[0.6 0.6 0.6], 'MarkerEdgeColor','k'); %[output:918d6367]
%Current agent action (bright)
h_agent       = plot(agent_tx(1), agent_ty(1), 'ws', 'MarkerSize', 14, ... %[output:918d6367]
                     'MarkerFaceColor', 'w', 'LineWidth', 1.5); %[output:918d6367]

% --- Brute-force optimum (red) ---
% Trail of past optima
h_trail_brute_force   = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), '-', ... %[output:918d6367]
                     'Color', [1 0 0 0.4], 'LineWidth', 1.2); %[output:918d6367]
% Past optimum markers (dim red)
h_past_brute_force    = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:918d6367]
                     'MarkerSize', 8, 'LineWidth', 1.0, ... %[output:918d6367]
                     'Color', [1 0.6 0.6]); %[output:918d6367]
% Current optimum (bright red)
h_opt_brute_force         = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:918d6367]
                     'MarkerSize', 16, 'LineWidth', 2.5); %[output:918d6367]


