x_boundaries_B = [psi_x_orig_B - dx/2, psi_x_orig_B(end) + dx/2];
y_boundaries_B = [psi_y_orig_B - dy/2, psi_y_orig_B(end) + dy/2];
for kx = 1:numel(x_boundaries_B)
    xline(x_boundaries_B(kx), '--w', 'LineWidth', 0.8);
end
